content.problemStatement:
In C++, **Multiple Level Inheritance** refers to a situation where a class inherits from another class, which itself inherits from a third class, and so on — creating a **chain of inheritance**.

It looks like a ladder:  
- **Grandparent Class → Parent Class → Child Class**

The child class has access to all accessible members (variables and methods) of its parent class and grandparent class, depending on access specifiers (`public`, `protected`, `private`).

This type of inheritance helps in creating **hierarchical models** and reusing code across several levels.


**Syntax**

```cpp
class Grandparent {
    // Grandparent class members
};

class Parent : public Grandparent {
    // Parent class members
};

class Child : public Parent {
    // Child class members
};
```

- `Parent` publicly inherits from `Grandparent`.
- `Child` publicly inherits from `Parent`.
- `Child` can access both `Parent` and `Grandparent` members (if accessible).

---

**Example**

```cpp
#include 
#include 
using namespace std;

// Grandparent Class
class Vehicle {
public:
    string modelName;

    Vehicle() {
        modelName = "Generic Vehicle";
    }

    void displayVehicleInfo() {
        cout << "Vehicle Model: " << modelName << endl;
    }
};

// Parent Class inheriting from Vehicle
class EngineVehicle : public Vehicle {
public:
    string engineType;

    EngineVehicle() {
        engineType = "Generic Engine";
    }

    void displayEngineInfo() {
        cout << "Engine Type: " << engineType << endl;
    }
};

// Child Class inheriting from EngineVehicle
class Car : public EngineVehicle {
public:
    int numberOfDoors;

    Car() {
        numberOfDoors = 4;
    }

    void displayCarInfo() {
        cout << "Number of Doors: " << numberOfDoors << endl;
    }
};

int main() {
    Car myCar;

    myCar.modelName = "Sedan";     // Inherited from Vehicle
    myCar.engineType = "Petrol";   // Inherited from EngineVehicle
    myCar.numberOfDoors = 4;       // Defined in Car

    myCar.displayVehicleInfo();    // Method from Vehicle
    myCar.displayEngineInfo();     // Method from EngineVehicle
    myCar.displayCarInfo();        // Method from Car

    return 0;
}
```

---

**Expected Output**

```default
Vehicle Model: Sedan
Engine Type: Petrol
Number of Doors: 4
```

